INSERT INTO reviews (id,customer_id,family_member_id,registered_business_location_id,rating,overall_rating,price_rating,service_rating,quality_rating,title,content,review_status,points_awarded,created_at) VALUES
('a1a1a1a1-b2b2-c3c3-d4d4-e5e5e5e50001','a1000001-0000-0000-0000-000000000001',NULL,'f1e2d3c4-b5a6-9870-fedc-ba9876540001',5,5,4,5,5,'Pizza napoletana autentica, da non perdere!','Ho provato la Pizzeria Da Napoli durante un viaggio. L impasto e soffice e leggero, il cornicione perfetto. Il forno a legna da quel profumo inconfondibile. Prezzi giusti per la qualita.','pending',0,NOW()-INTERVAL '5 hours'),
('a1a1a1a1-b2b2-c3c3-d4d4-e5e5e5e50002','a1000001-0000-0000-0000-000000000001',NULL,'f1e2d3c4-b5a6-9870-fedc-ba9876540002',4,4,4,5,4,'Officina professionale e onesta','Ho portato la mia Golf per un problema al cambio. Diagnosticato in meno di un ora con preventivo chiaro. Lavoro completato in giornata al prezzo concordato. Nessuna sorpresa.','pending',0,NOW()-INTERVAL '4 hours'),
('a1a1a1a1-b2b2-c3c3-d4d4-e5e5e5e50003','a1000001-0000-0000-0000-000000000001',NULL,'f1e2d3c4-b5a6-9870-fedc-ba9876540004',5,5,4,5,5,'Hotel fantastico, colazione da 5 stelle','Weekend romantico all Hotel Bellavista Roma. Camera spaziosa, vista sulla citta. Colazione eccezionale: cornetti freschi, frutta, formaggi DOP. Staff gentilissimo.','pending',0,NOW()-INTERVAL '3 hours'),
('b2b2b2b2-c3c3-d4d4-e5e5-f6f6f6f60001','a1000002-0000-0000-0000-000000000002','c3000001-0000-0000-0000-000000000001','f1e2d3c4-b5a6-9870-fedc-ba9876540001',5,5,5,5,5,'Ottima pizza, locale accogliente','Siamo venute per il compleanno di mia figlia Sofia. La pizza margherita era eccezionale, cosi come la frittura napoletana. Locale adatto alle famiglie, personale molto carino.','pending',0,NOW()-INTERVAL '6 hours'),
('b2b2b2b2-c3c3-d4d4-e5e5-f6f6f6f60002','a1000002-0000-0000-0000-000000000002',NULL,'f1e2d3c4-b5a6-9870-fedc-ba9876540003',4,4,3,4,4,'Bravi meccanici, tempi un po lunghi','Ho portato la mia auto per revisione e cambio gomme. Personale competente e cortese. L unico neo e l attesa: 3 ore anche con appuntamento. Ma il lavoro e stato fatto bene.','pending',0,NOW()-INTERVAL '7 hours'),
('b2b2b2b2-c3c3-d4d4-e5e5-f6f6f6f60003','a1000002-0000-0000-0000-000000000002',NULL,'f1e2d3c4-b5a6-9870-fedc-ba9876540005',4,4,3,4,4,'Hotel piacevole ma con qualche lacuna','Soggiorno di 3 notti. Camera pulita e silenziosa, personale gentile. Purtroppo la piscina era chiusa per manutenzione senza preavviso. Colazione un po ripetitiva.','pending',0,NOW()-INTERVAL '8 hours'),
('c3c3c3c3-d4d4-e5e5-f6f6-a7a7a7a70001','a1000002-0000-0000-0000-000000000002','c3000001-0000-0000-0000-000000000001','f1e2d3c4-b5a6-9870-fedc-ba9876540002',5,5,5,5,5,'Rapidi, competenti e prezzi giusti!','Mia mamma mi ha accompagnata e siamo rimaste molto soddisfatte. Hanno risolto in 2 ore un problema che ci avevano detto richiedesse un giorno intero. Prezzo inferiore alle aspettative!','pending',0,NOW()-INTERVAL '9 hours');
